// This file contains an example to demonstrate how to use Foxit PDF SDK to generate summary for annotation in PDF document.

// Include Foxit SDK header files.

#if defined(_WIN32) || defined(_WIN64)
#include <direct.h>
#else
#include <sys/stat.h>
#endif

#include "../../../include/common/fs_common.h"
#include "../../../include/pdf/fs_annotationsummary.h"

using namespace std;
using namespace foxit;
using namespace foxit::common;
using foxit::common::Library;
using namespace pdf;
using namespace annots;

static const char* sn = "XQSqpYXftiFIcjaUVzEYXWVFvT86aRH+NpxaYmpzjXt+knIjbaBmMQ==";
static const char* key = "";

#if defined(_WIN32) || defined(_WIN64)
static WString output_path = WString::FromLocal("../output_files/");
static WString input_path = WString::FromLocal("../input_files/");
#else
static WString output_path = WString::FromLocal("./output_files/");
static WString input_path = WString::FromLocal("./input_files/");
#endif

class SdkLibMgr {
public:
  SdkLibMgr() : is_initialize_(false){};
  ErrorCode Initialize() {
    ErrorCode error_code = Library::Initialize(sn, key);
    if (error_code != foxit::e_ErrSuccess) {
      printf("Library Initialize Error: %d\n", error_code);
    } else {
      is_initialize_ = true;
    }
    return error_code;

  }
  ~SdkLibMgr(){
    if(is_initialize_)
      Library::Release();
  }
private:
  bool is_initialize_;
};

int main(int argc, char *argv[])
{
  int err_ret = 0;
  SdkLibMgr sdk_lib_mgr;
  // Initialize library
  ErrorCode error_code = sdk_lib_mgr.Initialize();
  if (error_code != foxit::e_ErrSuccess) {
    return 1;
  }
  try {
    WString input_file = input_path + L"Annot_all.pdf";
    WString output_directory = output_path + L"annotation_summary/";
#if defined(_WIN32) || defined(_WIN64)
    _mkdir(String::FromUnicode(output_directory));
#else
    mkdir(String::FromUnicode(output_directory), S_IRWXU | S_IRWXG | S_IROTH | S_IXOTH);
#endif
    // Load PDF document.
    PDFDoc doc(input_file);
    ErrorCode error_code = doc.Load();
    if (error_code != foxit::e_ErrSuccess) {
      printf("The Doc [%s] Error: %d\n", (const char*)String::FromUnicode(input_file), error_code);
      return 1;
    }
    AnnotationSummary commentssummary = AnnotationSummary(doc);
    AnnotationSummarySettings settings;
    settings.SetSummaryLayout(AnnotationSummarySettings::e_SummaryLayoutSinglePageWithLine);
    settings.SetSortType(AnnotationSummarySettings::e_TypeSortByPage);
    settings.SetAnnotType(annots::Annot::e_UnknownType, true);
    settings.SetFileTitle(L"AnnotationSummaryFileTitle");
    settings.EnableOutputNoAnnotationPage(true);
    settings.SetConnectorLineColor(0xFFFF22);
    settings.SetConnectorLineOpacity(0.5f);
    WString summary_savepath = output_directory + L"AnnotationSummary_generate.pdf";

    commentssummary.StartSummarize(summary_savepath, settings, NULL);

    cout << "Generate annotation's summary to pdf successfully." << endl;
  }
  catch (const Exception& e) {
    cout << e.GetMessage() << endl;
    err_ret = 1;
  }

  return err_ret;
}
